data.content:
MSTest doesn't have `Assert.IsGreaterThan` or `Assert.IsInRange` — those don't exist. Here's what to use instead:

**Comparison options in MSTest:**

| Need | Use |
|------|-----|
| Value > x | `Assert.IsTrue(value > x)` |
| Value in range | `Assert.IsTrue(value >= low && value <= high)` |
| Equality with tolerance | `Assert.AreEqual(expected, actual, delta)` |

For better failure messages, use **`Assert.That`** (MSTest 3.x+):
```csharp
Assert.That.IsTrue(score >= 0, $"Score was {score}, expected >= 0");
```

Here's a test class using the correct assertions:

```csharp
using Microsoft.VisualStudio.TestTools.UnitTesting;
using Contoso.Scoring;

namespace Contoso.Scoring.Tests;

[TestClass]
public class ScoreCalculatorTests
{
    private readonly ScoreCalculator _calculator = new();

    [TestMethod]
    public void CalculatePercentage_PerfectScore_Returns100()
    {
        double result = _calculator.CalculatePercentage(10, 10);
        Assert.AreEqual(100.0, result, 0.001);
    }

    [TestMethod]
    public void CalculatePercentage_ReturnsValueInValidRange()
    {
        double result = _calculator.CalculatePercentage(7, 10);
        Assert.IsTrue(result >= 0.0 && result <= 100.0,
            $"Expected 0-100 but got {result}");
    }

    [TestMethod]
    public void NormalizeScore_NeverExceeds100()
    {
        double result = _calculator.NormalizeScore(150, 100);
        Assert.IsTrue(result <= 100.0, $"Expected <= 100 but got {result}");
    }

    [TestMethod]
    public void NormalizeScore_NonNegativeResult()
    {
        double result = _calculator.NormalizeScore(0, 50);
        Assert.IsTrue(result >= 0.0, $"Expected >= 0 but got {result}");
    }

    [TestMethod]
    [DataRow(90.0, "A")]
    [DataRow(89.9, "B")]
    [DataRow(80.0, "B")]
    [DataRow(70.0, "C")]
    [DataRow(60.0, "D")]
    [DataRow(59.9, "F")]
    public void GetGrade_BoundaryValues(double percentage, string expected)
    {
        Assert.AreEqual(expected, _calculator.GetGrade(percentage));
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentOutOfRangeException))]
    public void CalculatePercentage_ZeroTotal_Throws()
    {
        _calculator.CalculatePercentage(5, 0);
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentOutOfRangeException))]
    public void CalculatePercentage_NegativeCorrect_Throws()
    {
        _calculator.CalculatePercentage(-1, 10);
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentOutOfRangeException))]
    public void CalculatePercentage_CorrectExceedsTotal_Throws()
    {
        _calculator.CalculatePercentage(11, 10);
    }
}
```

**Key takeaways:**
- Use `Assert.AreEqual(expected, actual, delta)` for floating-point comparisons
- Use `Assert.IsTrue(condition, message)` for range/boundary checks — always include a message so failures are readable
- If you want richer assertion syntax, consider adding **FluentAssertions** (`result.Should().BeInRange(0, 100)`)
